package main

import (
	"bufio"
	"fmt"
	"math/rand"
	"net"
	"net/url"
	"os"
	"strconv"
	"strings"
	"sync/atomic"
	"time"
)

var (
	host      string
	port      string
	page      string
	method    string
	key       string
	start     = make(chan bool)
	sentCount uint64
	errCount  uint64
	proxies   []string
)

func init() {
	rand.Seed(time.Now().UnixNano())
}

// Generate a valid random IPv4 address
func randomIP() string {
	return fmt.Sprintf("%d.%d.%d.%d", rand.Intn(256), rand.Intn(256), rand.Intn(256), rand.Intn(256))
}

